<template><section class="page-pad"><div class="mb-6"><h1 class="text-3xl font-black">الحسابات والخزنة</h1><p class="text-muted mt-2">حركات الواردات والمصروفات ورصيد الخزنة</p></div><div class="grid gap-4 lg:grid-cols-3 mb-6"><div class="card p-5"><p class="text-muted">الواردات بالدينار</p><b class="stat-value text-emerald-500">{{money(data?.incomeIqd||0,'IQD')}}</b></div><div class="card p-5"><p class="text-muted">المصروفات بالدينار</p><b class="stat-value text-red-500">{{money(data?.expenseIqd||0,'IQD')}}</b></div><div class="card p-5"><p class="text-muted">رصيد الخزنة</p><b class="stat-value" :class="(data?.balanceIqd||0)<0?'text-red-500':'text-blue-500'">{{money(data?.balanceIqd||0,'IQD')}}</b></div></div><div v-if="(data?.balanceIqd||0)<0" class="mb-6 rounded-3xl border border-red-400/50 bg-red-500/10 p-5 font-bold text-red-500">تنبيه: رصيد الخزنة بالسالب.</div><div class="card overflow-x-auto"><table class="table"><thead><tr><th>النوع</th><th>المبلغ</th><th>العملة</th><th>الوصف</th><th>التاريخ</th></tr></thead><tbody><tr v-for="t in data?.transactions" :key="t.id"><td>{{t.type==='INCOME'?'وارد':'مصروف'}}</td><td>{{money(t.amount,t.currency)}}</td><td>{{t.currency}}</td><td>{{t.description}}</td><td>{{dateTimeText(t.createdAt)}}</td></tr></tbody></table></div></section></template>
